import { useState, useEffect, useRef, useCallback } from 'react';
import { useParams } from 'react-router-dom';
import {
  Chart,
  BubbleController,
  LinearScale,
  LogarithmicScale,
  PointElement,
  Tooltip,
  Legend,
} from 'chart.js';
import { api } from '../../../lib/api.js';
import { useT } from '../../../lib/I18nContext.jsx';
import { AdminCard, AdminAlert, AdminLoader } from '../../../components/ui/index.js';

Chart.register(BubbleController, LinearScale, LogarithmicScale, PointElement, Tooltip, Legend);

/** Focal length representative midpoint (mm, 35mm eq.) and color per bin */
const BIN_META = {
  ultra_wide:  { x: 14,  color: '#3b82f6' },
  wide:        { x: 24,  color: '#06b6d4' },
  wide_std:    { x: 32,  color: '#10b981' },
  normal:      { x: 43,  color: '#84cc16' },
  portrait:    { x: 68,  color: '#f59e0b' },
  short_tele:  { x: 110, color: '#f97316' },
  tele:        { x: 168, color: '#ef4444' },
  super_tele:  { x: 270, color: '#a855f7' },
};

const BIN_LABEL_KEY = {
  ultra_wide:  'insights_bin_ultra_wide',
  wide:        'insights_bin_wide',
  wide_std:    'insights_bin_wide_std',
  normal:      'insights_bin_normal',
  portrait:    'insights_bin_portrait',
  short_tele:  'insights_bin_short_tele',
  tele:        'insights_bin_tele',
  super_tele:  'insights_bin_super_tele',
};

function FocalBubbleChart({ bins, t, selectedKey, onBinClick }) {
  const canvasRef = useRef(null);
  const chartRef  = useRef(null);
  // Keep a stable ref to the bins→key mapping so the click handler can read it
  const binsRef   = useRef(bins);
  binsRef.current = bins;

  useEffect(() => {
    if (!canvasRef.current || !bins.length) return;

    const maxCount = bins[0].count;
    function r(count) { return 10 + Math.sqrt(count / maxCount) * 38; }

    const datasets = bins.map(bin => {
      const meta      = BIN_META[bin.key] ?? { x: 50, color: '#888' };
      const isSelected = bin.key === selectedKey;
      return {
        label: t(BIN_LABEL_KEY[bin.key]) || bin.label,
        data: [{ x: meta.x, y: 1, r: r(bin.count), count: bin.count, key: bin.key }],
        backgroundColor: meta.color + (isSelected ? 'ff' : 'b0'),
        borderColor:     meta.color,
        borderWidth:     isSelected ? 3 : 2,
        hoverBackgroundColor: meta.color + 'e0',
      };
    });

    if (chartRef.current) chartRef.current.destroy();

    chartRef.current = new Chart(canvasRef.current, {
      type: 'bubble',
      data: { datasets },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        animation: { duration: 400 },
        cursor: 'pointer',
        onClick: (_evt, elements) => {
          if (!elements.length) { onBinClick(null); return; }
          const key = binsRef.current[elements[0].datasetIndex]?.key ?? null;
          onBinClick(key);
        },
        scales: {
          x: {
            type: 'logarithmic',
            min: 8,
            max: 400,
            grid: { color: '#e5e7eb' },
            border: { display: false },
            title: { display: true, text: 'Focal length (mm, 35mm eq.)', color: '#6b7280', font: { size: 11 } },
            ticks: { color: '#6b7280', font: { size: 11 }, maxTicksLimit: 8, callback: v => `${v}mm` },
          },
          y: { display: false, min: 0, max: 2 },
        },
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              title: ctx => ctx[0].dataset.label,
              label: ctx => ` ${ctx.raw.count} photos — click to browse`,
            },
          },
        },
      },
    });

    return () => chartRef.current?.destroy();
  }, [bins, selectedKey, t]);  // re-render when selection changes

  return (
    <div style={{ position: 'relative', height: 200, cursor: 'pointer' }}>
      <canvas ref={canvasRef} />
    </div>
  );
}

/**
 * Fullscreen lightbox — keyboard (← → Esc) + click backdrop to close.
 * Uses the existing /preview endpoint (800px, already authenticated).
 */
function PhotoLightbox({ photos, index, galleryId, onClose, onPrev, onNext }) {
  // Keyboard navigation
  useEffect(() => {
    function onKey(e) {
      if (e.key === 'Escape')     onClose();
      if (e.key === 'ArrowLeft')  onPrev();
      if (e.key === 'ArrowRight') onNext();
    }
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose, onPrev, onNext]);

  if (index === null) return null;

  const filename = photos[index];
  const src = `/api/galleries/${galleryId}/photos/${encodeURIComponent(filename)}/preview`;
  const total = photos.length;

  return (
    <div
      onClick={onClose}
      style={{
        position: 'fixed', inset: 0, zIndex: 10000,
        background: 'rgba(0,0,0,0.92)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
      }}
    >
      {/* Prev */}
      <button
        onClick={e => { e.stopPropagation(); onPrev(); }}
        style={navBtn('left')}
        aria-label="Previous"
        disabled={index === 0}
      >
        <i className="fas fa-chevron-left" />
      </button>

      {/* Image */}
      <img
        key={filename}
        src={src}
        alt={filename}
        onClick={e => e.stopPropagation()}
        style={{
          maxWidth: '88vw', maxHeight: '88vh',
          objectFit: 'contain',
          borderRadius: 4,
          boxShadow: '0 8px 40px rgba(0,0,0,0.6)',
          display: 'block',
        }}
      />

      {/* Next */}
      <button
        onClick={e => { e.stopPropagation(); onNext(); }}
        style={navBtn('right')}
        aria-label="Next"
        disabled={index === total - 1}
      >
        <i className="fas fa-chevron-right" />
      </button>

      {/* Counter + filename — top center */}
      <div style={{
        position: 'absolute', top: 16, left: '50%', transform: 'translateX(-50%)',
        color: 'rgba(255,255,255,0.8)', fontSize: '0.82rem', textAlign: 'center',
        pointerEvents: 'none',
      }}>
        <span>{index + 1} / {total}</span>
        <span style={{ marginLeft: 12, opacity: 0.5 }}>{filename}</span>
      </div>

      {/* Close — top right */}
      <button
        onClick={e => { e.stopPropagation(); onClose(); }}
        style={{
          position: 'absolute', top: 12, right: 16,
          background: 'none', border: 'none', color: 'rgba(255,255,255,0.7)',
          fontSize: '1.4rem', cursor: 'pointer', lineHeight: 1,
        }}
        aria-label="Close"
      >
        <i className="fas fa-times" />
      </button>
    </div>
  );
}

function navBtn(side) {
  return {
    position: 'absolute', [side]: 16, top: '50%', transform: 'translateY(-50%)',
    background: 'rgba(255,255,255,0.12)', border: 'none', borderRadius: '50%',
    width: 48, height: 48, color: '#fff', fontSize: '1.1rem',
    cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center',
    transition: 'background 0.15s',
    zIndex: 1,
  };
}

export default function GalleryInsightsPage() {
  const t = useT();
  const { galleryId } = useParams();

  const [stats,       setStats]       = useState(null);
  const [loading,     setLoading]     = useState(true);
  const [error,       setError]       = useState('');
  const [selectedKey, setSelectedKey] = useState(null);
  const [lightboxIdx, setLightboxIdx] = useState(null);
  const [lightboxPhotos, setLightboxPhotos] = useState([]);

  const openLightbox = useCallback((photos, idx) => {
    setLightboxPhotos(photos);
    setLightboxIdx(idx);
  }, []);
  const closeLightbox = useCallback(() => setLightboxIdx(null), []);
  const prevPhoto = useCallback(() => setLightboxIdx(i => Math.max(0, i - 1)), []);
  const nextPhoto = useCallback(() => setLightboxIdx(i => Math.min(lightboxPhotos.length - 1, i + 1)), [lightboxPhotos.length]);

  useEffect(() => {
    api.getFocalStats(galleryId)
      .then(setStats)
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, [galleryId]);

  if (loading) return <AdminLoader label={t('insights_focal_loading')} />;
  if (error)   return <AdminAlert message={error} className="m-3" />;

  const { total, withData, bins, dominant } = stats;

  const isEmpty = total === 0;
  const noExif  = withData === 0 && total > 0;
  const missing = total - withData;
  const pct     = total > 0 ? Math.round((withData / total) * 100) : 0;

  // Full list in focal order (for the legend table below the chart)
  const binsOrdered = [...bins].sort(
    (a, b) => (BIN_META[a.key]?.x ?? 0) - (BIN_META[b.key]?.x ?? 0)
  );

  return (
    <div className="p-3">
      <PhotoLightbox
        photos={lightboxPhotos}
        index={lightboxIdx}
        galleryId={galleryId}
        onClose={closeLightbox}
        onPrev={prevPhoto}
        onNext={nextPhoto}
      />

      <h4 className="mb-3">{t('insights_focal_section')}</h4>

      {isEmpty && <AdminAlert variant="secondary" message={t('insights_focal_not_built')} />}
      {!isEmpty && noExif && <AdminAlert variant="warning" message={t('insights_focal_no_data')} />}

      {!isEmpty && !noExif && (
        <>
          {/* KPI row */}
          <div className="d-flex gap-3 mb-4 flex-wrap">
            <div className="card px-4 py-3 text-center" style={{ minWidth: 110 }}>
              <div className="fs-3 fw-bold text-primary">{pct}%</div>
              <div className="text-muted small">focal data</div>
            </div>
            <div className="card px-4 py-3 text-center" style={{ minWidth: 110 }}>
              <div className="fs-3 fw-bold text-secondary">{withData}</div>
              <div className="text-muted small">photos analysed</div>
            </div>
            {dominant && (
              <div className="card px-4 py-3 text-center" style={{ minWidth: 140 }}>
                <div className="fw-semibold" style={{ color: BIN_META[dominant]?.color }}>
                  {t(BIN_LABEL_KEY[dominant])}
                </div>
                <div className="text-muted small">{t('insights_focal_dominant')}</div>
              </div>
            )}
          </div>

          {/* Bubble chart */}
          <AdminCard className="mb-3">
            <FocalBubbleChart
              bins={bins}
              t={t}
              selectedKey={selectedKey}
              onBinClick={key => setSelectedKey(prev => prev === key ? null : key)}
            />
          </AdminCard>

          {/* Photo thumbnails for selected bin */}
          {selectedKey && (() => {
            const bin = bins.find(b => b.key === selectedKey);
            if (!bin) return null;
            return (
              <AdminCard
                className="mb-3"
                title={t(BIN_LABEL_KEY[selectedKey])}
                headerRight={
                  <button
                    type="button"
                    className="btn-close"
                    aria-label="Close"
                    onClick={() => setSelectedKey(null)}
                  />
                }
              >
                <div style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fill, minmax(90px, 1fr))',
                  gap: '0.5rem',
                }}>
                  {bin.photos.map((filename, idx) => (
                    <div
                      key={filename}
                      title={filename}
                      onClick={() => openLightbox(bin.photos, idx)}
                      style={{ borderRadius: 4, overflow: 'hidden', aspectRatio: '1', background: '#f3f4f6', cursor: 'pointer' }}
                    >
                      <img
                        src={`/api/galleries/${galleryId}/photos/${encodeURIComponent(filename)}/preview`}
                        alt={filename}
                        style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block', transition: 'transform 0.15s' }}
                        loading="lazy"
                        onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.04)'}
                        onMouseLeave={e => e.currentTarget.style.transform = ''}
                      />
                    </div>
                  ))}
                </div>
                <p className="text-muted small mb-0 mt-2">{bin.count} photo{bin.count > 1 ? 's' : ''}</p>
              </AdminCard>
            );
          })()}

          {/* Legend table */}
          <AdminCard>
            <table className="table table-sm mb-0">
              <tbody>
                {binsOrdered.map(bin => {
                  const meta  = BIN_META[bin.key] ?? {};
                  const share = withData > 0 ? Math.round((bin.count / withData) * 100) : 0;
                  return (
                    <tr key={bin.key}>
                      <td style={{ width: 12, padding: '6px 8px' }}>
                        <span style={{ display: 'inline-block', width: 10, height: 10, borderRadius: '50%', background: meta.color }} />
                      </td>
                      <td style={{ fontSize: '0.85rem' }}>{t(BIN_LABEL_KEY[bin.key]) || bin.label}</td>
                      <td className="text-muted text-end" style={{ fontSize: '0.85rem', width: 60 }}>{bin.count}</td>
                      <td style={{ width: 80 }}>
                        <div className="progress" style={{ height: 6 }}>
                          <div className="progress-bar" role="progressbar"
                            style={{ width: `${share}%`, background: meta.color }} />
                        </div>
                      </td>
                      <td className="text-muted text-end" style={{ fontSize: '0.75rem', width: 40 }}>{share}%</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </AdminCard>

          {missing > 0 && (
            <p className="text-muted small mt-2">
              {t('insights_focal_missing_hint').replace('{missing}', missing)}
            </p>
          )}
        </>
      )}
    </div>
  );
}
